'use client';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { LayoutDashboard, ShoppingCart, Package, FileText, Users, LogOut, Settings, BarChart3 } from 'lucide-react';
import { createClient } from '@/utils/supabase/client';

const DashboardSidebar = ({ isOpen, onClose, userRole }) => {
  const pathname = usePathname();
  const router = useRouter();
  const supabase = createClient();

  const handleLogout = async () => {
    await supabase.auth.signOut();
    router.push('/login');
    router.refresh();
  };

  const navItems = [
    { name: 'Tablero', href: '/dashboard', icon: LayoutDashboard },
    { name: 'Pedidos', href: '/dashboard/pedidos', icon: ShoppingCart },
    { name: 'Inventarios', href: '/dashboard/inventarios', icon: Package },
  ];

  // Admin-only items
  if (userRole === 'admin') {
    navItems.push(
      { name: 'Estadísticas', href: '/dashboard/estadisticas', icon: BarChart3 },
      { name: 'CMS Landing', href: '/dashboard/cms', icon: FileText },
      { name: 'Usuarios', href: '/dashboard/usuarios', icon: Users }
    );
  }

  return (
    <>
      <aside className={`sidebar ${isOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <img src="/logo-transparent.png" alt="Greenland Products" className="sidebar-logo" />
          <div className="logo-text">
            <span className="brand">GREENLAND</span>
            <span className="sub">DASHBOARD</span>
          </div>
        </div>

        <nav className="sidebar-nav">
          <div className="nav-section">
            <span className="nav-label">MENU PRINCIPAL</span>
            {navItems.map((item) => {
              const isActive = pathname === item.href;
              return (
                <Link
                  key={item.href}
                  href={item.href}
                  className={`nav-link ${isActive ? 'active' : ''}`}
                  onClick={onClose}
                >
                  <item.icon size={20} />
                  <span>{item.name}</span>
                </Link>
              );
            })}
          </div>
        </nav>

        <div className="sidebar-footer">
          <button onClick={handleLogout} className="nav-link logout-btn">
            <LogOut size={20} />
            <span>Cerrar Sesión</span>
          </button>
          <div className="user-info">
            <small>{userRole === 'admin' ? 'Administrador' : 'Distribuidor'}</small>
          </div>
        </div>
      </aside>

      {/* Mobile Overlay */}
      {isOpen && <div className="sidebar-overlay" onClick={onClose}></div>}

      <style jsx>{`
        .sidebar {
          position: fixed;
          top: 0;
          left: 0;
          width: var(--layout-sidebar-width);
          height: 100vh;
          background: #0f0f1a;
          border-right: 1px solid rgba(255, 255, 255, 0.08);
          display: flex;
          flex-direction: column;
          z-index: 50;
          transition: transform 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        }

        .sidebar-header {
          padding: 1.5rem;
          display: flex;
          align-items: center;
          gap: 0.75rem;
          border-bottom: 1px solid rgba(255, 255, 255, 0.05);
        }

        .sidebar-logo {
          width: 32px;
          height: auto;
        }

        .logo-text {
          display: flex;
          flex-direction: column;
        }

        .brand {
          font-weight: 700;
          font-size: 1rem;
          color: white;
          line-height: 1;
        }

        .sub {
          font-size: 0.65rem;
          color: var(--color-primary);
          letter-spacing: 0.1em;
        }

        .sidebar-nav {
          flex: 1;
          padding: 1.5rem 1rem;
          overflow-y: auto;
        }

        .nav-section {
          margin-bottom: 2rem;
          display: flex;
          flex-direction: column;
          gap: 0.5rem;
        }

        .nav-label {
          font-size: 0.7rem;
          color: var(--color-text-muted);
          padding-left: 1rem;
          margin-bottom: 0.5rem;
          font-weight: 600;
          letter-spacing: 0.05em;
        }

        .nav-link {
          display: flex;
          align-items: center;
          gap: 1rem;
          padding: 0.75rem 1rem;
          color: var(--color-text-muted);
          border-radius: var(--radius-md);
          transition: all 0.2s;
          font-weight: 500;
          font-size: 0.9rem;
          background: transparent;
          border: none;
          width: 100%;
          cursor: pointer;
          text-align: left;
        }

        .nav-link:hover {
          background: rgba(255, 255, 255, 0.05);
          color: white;
        }

        .nav-link.active {
          background: rgba(74, 222, 32, 0.1);
          color: var(--color-primary);
          border-left: 3px solid var(--color-primary);
        }

        .sidebar-footer {
          padding: 1.5rem;
          border-top: 1px solid rgba(255, 255, 255, 0.05);
        }

        .logout-btn {
          color: #ef4444;
        }
        .logout-btn:hover {
          background: rgba(239, 68, 68, 0.1);
          color: #fca5a5;
        }

        .user-info {
          margin-top: 1rem;
          text-align: center;
          color: var(--color-text-muted);
        }

        @media (max-width: 768px) {
          .sidebar {
            transform: translateX(-100%);
          }
          .sidebar.open {
            transform: translateX(0);
          }
          .sidebar-overlay {
            position: fixed;
            inset: 0;
            background: rgba(0, 0, 0, 0.5);
            backdrop-filter: blur(4px);
            z-index: 40;
          }
        }
      `}</style>
    </>
  );
};

export default DashboardSidebar;
